const req = $node['Parse Request'].json;
return [{
  json: {
    status: 'p1_failed',
    req_id: req.req_id,
    message: 'P1 spec split failed, escalating to human'
  }
}];

// TODO: Check if target files are occupied by other active tasks
// For now, pass through - implement when parallel tasks are running
const req = $node['Parse Request'].json;
return [{
  json: {
    ...req,
    conflict_check: 'passed',
    conflicting_files: []
  }
}];

// TODO: Query active namespace count from cluster state
// For now, assume pool is available
const maxConcurrent = 3;
const activeNamespaces = 0; // Replace with actual kubectl query
return [{
  json: {
    pool_available: activeNamespaces < maxConcurrent,
    active_count: activeNamespaces,
    max_concurrent: maxConcurrent
  }
}];

const result = $input.first().json;
const state = $node['Parse Request'].json;
const elapsed = Date.now() - state.start_time;
const tokens = (state.total_tokens || 0) + (result.tokens_used || 0);

return [{
  json: {
    req_id: state.req_id,
    title: state.title,
    scope: state.scope,
    round: state.round + 1,
    total_tokens: tokens,
    start_time: state.start_time,
    elapsed_ms: elapsed,
    max_rounds: state.max_rounds,
    max_duration_ms: state.max_duration_ms,
    max_tokens: state.max_tokens,
    success: result.success === true,
    layer_results: result.layer_results || {},
    failed_layer: result.failed_layer || null,
    error_summary: result.error_summary || null
  }
}];

const s = $input.first().json;
const tripped = (
  s.round >= s.max_rounds ||
  s.elapsed_ms >= s.max_duration_ms ||
  s.total_tokens >= s.max_tokens
);
const reason = [];
if (s.round >= s.max_rounds) reason.push(`rounds ${s.round}/${s.max_rounds}`);
if (s.elapsed_ms >= s.max_duration_ms) reason.push(`time ${Math.round(s.elapsed_ms/1000)}s/${s.max_duration_ms/1000}s`);
if (s.total_tokens >= s.max_tokens) reason.push(`tokens ${s.total_tokens}/${s.max_tokens}`);

return [{
  json: {
    ...s,
    breaker_tripped: tripped,
    breaker_reason: reason.join(', ') || 'none'
  }
}];

const s = $input.first().json;
// TODO: Create Issue via vibe-kanban API for human escalation
return [{
  json: {
    status: 'breaker_tripped',
    req_id: s.req_id,
    title: s.title,
    round: s.round,
    total_tokens: s.total_tokens,
    elapsed_ms: s.elapsed_ms,
    breaker_reason: s.breaker_reason,
    failed_layer: s.failed_layer,
    error_summary: s.error_summary,
    message: 'Circuit breaker tripped. Escalating to human. Debug namespace preserved for investigation.'
  }
}];

const s = $input.first().json;
// TODO: Create sub-issue via vibe-kanban API with:
// - failed layer, error summary, round number, token usage, elapsed time
return [{
  json: {
    ...s,
    sub_issue_created: true,
    sub_issue_title: `[${s.req_id}] Round ${s.round} failed at ${s.failed_layer}: ${s.error_summary}`
  }
}];

// Pass updated state back to dispatch loop
const s = $input.first().json;
return [{
  json: {
    req_id: s.req_id,
    title: s.title,
    description: s.description || '',
    scope: s.scope,
    round: s.round,
    total_tokens: s.total_tokens,
    start_time: s.start_time,
    max_rounds: s.max_rounds,
    max_duration_ms: s.max_duration_ms,
    max_tokens: s.max_tokens
  }
}];

const s = $input.first().json;
// TODO: Close the requirement issue via vibe-kanban API
return [{
  json: {
    ...s,
    issue_closed: true
  }
}];

// TODO: Check merge queue, wait if another PR is merging
// For now, pass through
const s = $input.first().json;
return [{
  json: {
    ...s,
    merge_slot_acquired: true
  }
}];

